import net from "node:net";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
vi.mock("./ensure.js", () => ({
    ensureDaemon: vi.fn().mockResolvedValue(undefined),
}));
import { DaemonClient, resolveAgentSessionKey } from "./client.js";
function tmpSocketPath() {
    return path.join(os.tmpdir(), `bitfab-test-client-${Date.now()}-${Math.random().toString(36).slice(2)}.sock`);
}
describe("DaemonClient", () => {
    let mockServer;
    let socketPath;
    beforeEach(() => {
        socketPath = tmpSocketPath();
    });
    afterEach(() => {
        if (mockServer) {
            mockServer.close();
        }
    });
    function startMockServer(handler) {
        return new Promise((resolve) => {
            mockServer = net.createServer(handler);
            mockServer.listen(socketPath, resolve);
        });
    }
    function lineResponder(respond) {
        return (socket) => {
            let buffer = "";
            socket.on("data", (chunk) => {
                buffer += chunk.toString();
                let idx = buffer.indexOf("\n");
                while (idx !== -1) {
                    const line = buffer.slice(0, idx).trim();
                    buffer = buffer.slice(idx + 1);
                    if (line) {
                        const cmd = JSON.parse(line);
                        const res = respond(cmd);
                        if (res) {
                            socket.write(`${JSON.stringify(res)}\n`);
                        }
                    }
                    idx = buffer.indexOf("\n");
                }
            });
        };
    }
    it("connects and pings", async () => {
        await startMockServer(lineResponder(() => ({ ok: true })));
        const client = new DaemonClient(socketPath);
        await client.connect();
        await client.ping();
        client.destroy();
    });
    it("opens a session", async () => {
        await startMockServer(lineResponder((cmd) => {
            if (cmd.cmd === "open") {
                return {
                    ok: true,
                    sessionId: "session-123",
                    browserConnected: false,
                    reconnected: false,
                };
            }
            return { ok: true };
        }));
        const client = new DaemonClient(socketPath);
        await client.connect();
        const res = await client.open({
            key: "test-key",
            serviceUrl: "https://example.com",
            apiKey: "key-123",
        });
        expect(res.sessionId).toBe("session-123");
        expect(res.reconnected).toBe(false);
        client.destroy();
    });
    it("receives pushed events", async () => {
        let serverSocket = null;
        await startMockServer((socket) => {
            serverSocket = socket;
            let buffer = "";
            socket.on("data", (chunk) => {
                buffer += chunk.toString();
                let idx = buffer.indexOf("\n");
                while (idx !== -1) {
                    buffer = buffer.slice(idx + 1);
                    socket.write(`${JSON.stringify({ ok: true, sessionId: "s-1", browserConnected: false, reconnected: false })}\n`);
                    idx = buffer.indexOf("\n");
                }
            });
        });
        const client = new DaemonClient(socketPath);
        await client.connect();
        await client.open({
            key: "push-test",
            serviceUrl: "https://example.com",
            apiKey: "key-123",
        });
        const pushPromise = new Promise((resolve) => {
            client.onEvent(resolve);
        });
        serverSocket.write(`${JSON.stringify({
            event: "studio:navigated",
            sessionId: "s-1",
            key: "push-test",
            data: { path: "/studio/traces" },
        })}\n`);
        const push = await pushPromise;
        expect(push.event).toBe("studio:navigated");
        expect(push.data.path).toBe("/studio/traces");
        client.destroy();
    });
    it("fires onDisconnect when the daemon drops the connection", async () => {
        let serverSocket = null;
        await startMockServer((socket) => {
            serverSocket = socket;
        });
        const client = new DaemonClient(socketPath);
        await client.connect();
        const disconnect = new Promise((resolve) => {
            client.onDisconnect(resolve);
        });
        serverSocket.destroy();
        const err = await disconnect;
        expect(err).toBeInstanceOf(Error);
        client.destroy();
    });
    it("does not fire onDisconnect on a deliberate destroy", async () => {
        await startMockServer(lineResponder(() => ({ ok: true })));
        const client = new DaemonClient(socketPath);
        await client.connect();
        const onDisconnect = vi.fn();
        client.onDisconnect(onDisconnect);
        client.destroy();
        // Give the socket close event a tick to fire.
        await new Promise((resolve) => setTimeout(resolve, 10));
        expect(onDisconnect).not.toHaveBeenCalled();
    });
    it("throws on error response", async () => {
        await startMockServer(lineResponder(() => ({ ok: false, error: "test error" })));
        const client = new DaemonClient(socketPath);
        await client.connect();
        await expect(client.close("nonexistent")).rejects.toThrow("test error");
        client.destroy();
    });
    it("gets status", async () => {
        await startMockServer(lineResponder((cmd) => {
            if (cmd.cmd === "status") {
                return {
                    ok: true,
                    sessions: [
                        {
                            key: "k1",
                            sessionId: "s1",
                            browserPid: 123,
                            browserConnected: true,
                            connectedClients: 1,
                            lastActivity: Date.now(),
                        },
                    ],
                };
            }
            return { ok: true };
        }));
        const client = new DaemonClient(socketPath);
        await client.connect();
        const status = await client.status();
        expect(status.sessions).toHaveLength(1);
        expect(status.sessions[0].key).toBe("k1");
        client.destroy();
    });
    it("clears a session and returns the cleared count", async () => {
        let received = null;
        await startMockServer(lineResponder((cmd) => {
            if (cmd.cmd === "clear") {
                received = cmd;
                return { ok: true, cleared: 1 };
            }
            return { ok: true };
        }));
        const client = new DaemonClient(socketPath);
        await client.connect();
        const cleared = await client.clear("s-1");
        expect(cleared).toBe(1);
        expect(received).toEqual({ cmd: "clear", sessionId: "s-1" });
        client.destroy();
    });
});
describe("resolveAgentSessionKey", () => {
    const originalEnv = process.env;
    beforeEach(() => {
        process.env = { ...originalEnv };
    });
    afterEach(() => {
        process.env = originalEnv;
    });
    it("returns CLAUDE_CODE_SESSION_ID when set", () => {
        process.env.CLAUDE_CODE_SESSION_ID = "claude-123";
        expect(resolveAgentSessionKey()).toBe("claude-123");
    });
    it("returns CURSOR_SESSION_ID when set", () => {
        delete process.env.CLAUDE_CODE_SESSION_ID;
        process.env.CURSOR_SESSION_ID = "cursor-456";
        expect(resolveAgentSessionKey()).toBe("cursor-456");
    });
    it("returns CODEX_THREAD_ID when set", () => {
        delete process.env.CLAUDE_CODE_SESSION_ID;
        delete process.env.CURSOR_SESSION_ID;
        process.env.CODEX_THREAD_ID = "codex-789";
        expect(resolveAgentSessionKey()).toBe("codex-789");
    });
    it("prefers CLAUDE_CODE_SESSION_ID over others", () => {
        process.env.CLAUDE_CODE_SESSION_ID = "claude-first";
        process.env.CURSOR_SESSION_ID = "cursor-second";
        process.env.CODEX_THREAD_ID = "codex-third";
        expect(resolveAgentSessionKey()).toBe("claude-first");
    });
});
